// Extract text from claude-bridge.py response
const responseText = items[0].json.output.trim();

// Parse the JSON array — handle edge case where model wraps in backticks
let ideas;
try {
  ideas = JSON.parse(responseText);
} catch (e) {
  const stripped = responseText.replace(/^```json?\n?|```$/gm, '').trim();
  try {
    ideas = JSON.parse(stripped);
  } catch (e2) {
    const match = stripped.match(/(\[\s*\{[\s\S]*\}\s*\])/);
    if (!match) throw new Error('Could not parse ideas. Raw: ' + responseText.slice(0, 300));
    ideas = JSON.parse(match[1]);
  }
}

if (!Array.isArray(ideas)) throw new Error('Expected JSON array, got: ' + typeof ideas);

// Normalize a field value — handles string, array, number, or null
function str(val) {
  if (val === null || val === undefined) return '';
  if (Array.isArray(val)) return val.join(', ');
  return String(val).trim();
}

return ideas.map(idea => ({
  json: {
    topic:           str(idea.topic),
    angle:           str(idea.angle),
    key_evidence:    str(idea.key_evidence),
    key_researchers: str(idea.key_researchers),
    hook_style:      str(idea.hook_style),
    tone_dial:       str(idea.tone_dial || 7),
    related_video:   str(idea.related_video) || 'none yet'
  }
}));

// Collect all existing topic strings from the sheet
const existingRows = $('Read Existing Topics').all();
const existingTopics = existingRows
  .map(row => (row.json.TOPIC || '').toLowerCase().trim())
  .filter(t => t.length > 0);

// Helper: extract significant words (length > 3, not stop words)
const STOP_WORDS = new Set(['that','this','with','from','have','been','were','they','their','what','when','where','which','will','would','could','should','about','than','then','into','over','after','before','under','above','between','through','during','found','built','used','made']);

function sigWords(str) {
  return str.toLowerCase()
    .replace(/[^a-z0-9\s]/g, '')
    .split(/\s+/)
    .filter(w => w.length > 3 && !STOP_WORDS.has(w));
}

// Get newly generated ideas (all items in current run)
const newIdeas = items;
const uniqueIdeas = [];

for (const idea of newIdeas) {
  const topic = (idea.json.topic || '').toLowerCase().trim();

  // 1. Exact match
  if (existingTopics.includes(topic)) continue;

  // 2. Key-word overlap: flag as duplicate if >=60% of significant words match any existing topic
  const newWords = sigWords(topic);
  const isDuplicate = newWords.length > 0 && existingTopics.some(existing => {
    const existWords = sigWords(existing);
    if (existWords.length === 0) return false;
    const overlap = newWords.filter(w => existWords.includes(w)).length;
    return overlap / newWords.length >= 0.6;
  });

  if (!isDuplicate) uniqueIdeas.push(idea);
}

return uniqueIdeas.length > 0 ? uniqueIdeas : [{ json: { __noNewIdeas: true } }];
